css:
.loader {color: var(--loader-color, #0891b2);
  --loader-secondary-color: #22d3ee;
  --loader-bg: #ffffff;
  width: 60px;
  height: 25px;
  border: 2px solid;
  box-sizing: border-box;
  border-radius: 50%;
  display: grid;
  animation: l2 2s infinite linear;
}.loader:before,.loader:after {content: "";
  grid-area: 1/1;
  border: inherit;
  border-radius: 50%;
  animation: inherit;
  animation-duration: 3s;
}.loader:before {--s:-1;
}@keyframes l2 {100% {transform: scale(calc(var(--s,1)*1turn))}}
